import React from 'react';
import { motion } from 'framer-motion';

interface Agent {
    id: string;
    name: string;
    status: 'IDLE' | 'EXEC' | 'ERR_NODE';
}

const agents: Agent[] = [
    { id: '1', name: 'AGENT_01', status: 'IDLE' },
    { id: '2', name: 'AGENT_02', status: 'EXEC' },
    { id: '3', name: 'AGENT_03', status: 'ERR_NODE' },
    { id: '4', name: 'AGENT_04', status: 'IDLE' },
];

export const AgentRegistry: React.FC = () => {
    return (
        <div className="flex flex-col gap-1 p-2">
            {agents.map((agent, i) => (
                <motion.div
                    key={agent.id}
                    initial={{ opacity: 0, x: 10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className={`flex items-center justify-between p-3 rounded-lg border border-transparent transition-all cursor-pointer ${agent.status === 'ERR_NODE'
                            ? 'bg-red-900/10 border-red-900/30'
                            : 'hover:bg-slate-900/50 hover:border-[#2A2A2A]'
                        }`}
                >
                    <div className="flex items-center gap-3">
                        {agent.status === 'IDLE' && (
                            <span className="w-2 h-2 rounded-full bg-white opacity-40"></span>
                        )}
                        {agent.status === 'EXEC' && (
                            <span className="w-2 h-2 rounded-full border border-white flex items-center justify-center p-[1px]">
                                <span className="w-1 h-1 bg-white rounded-full"></span>
                            </span>
                        )}
                        {agent.status === 'ERR_NODE' && (
                            <span className="material-symbols-outlined text-[#FF3B30] text-[12px] font-bold">warning</span>
                        )}

                        <span className={`text-sm font-mono ${agent.status === 'ERR_NODE' ? 'text-[#FF3B30] font-bold' :
                                agent.status === 'EXEC' ? 'text-white font-bold' : 'text-slate-200'
                            }`}>
                            {agent.name}
                        </span>
                    </div>

                    <span className={`text-[10px] font-mono tracking-tighter uppercase ${agent.status === 'ERR_NODE' ? 'text-[#FF3B30]' :
                            agent.status === 'EXEC' ? 'text-white' : 'text-slate-500'
                        }`}>
                        {agent.status}
                    </span>
                </motion.div>
            ))}

            {/* Decorative dots to fill space if needed */}
            <div className="mt-4 flex flex-col gap-2 px-3 opacity-10">
                {[...Array(3)].map((_, i) => (
                    <div key={i} className="flex justify-between items-center">
                        <div className="h-2 w-16 bg-white rounded-full" />
                        <div className="h-2 w-4 bg-white rounded-full" />
                    </div>
                ))}
            </div>
        </div>
    );
};
